import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import 'package:go_router/go_router.dart'; import '../../../../app/router/app_router.dart'; import '../providers/notification_providers.dart';
class NotificationIcon extends ConsumerWidget{const NotificationIcon({super.key}); @override Widget build(BuildContext context,WidgetRef ref){final count=ref.watch(unreadNotificationCountProvider).valueOrNull??0; return IconButton(onPressed:()=>context.push(AppRoutes.notifications),icon:Badge(isLabelVisible:count>0,label:Text(count>99?'99+':'$count'),child:const Icon(Icons.notifications_outlined)));}}
